text:
{
  "formal_minutes": {
    "decisions": {
      "confirmed": [
        "스모크 테스트 통과 시 공개 릴리스 목표를 금요일 15:00 KST로 확정한다.",
        "packageName 불일치가 발생하면 smoke-theme-pack.mjs를 바로 수정·무시 처리하지 않고, 먼저 패키지 설정(계약/구성)을 점검하며 계약 자체가 잘못된 경우에만 스크립트를 검토한다."
      ],
      "rejected_proposals": [
        "Hara가 제안한 'smoke-theme-pack.mjs에서 packageName 불일치 무시' 제안은 회의에서 반려됨."
      ],
      "internal_stretch_goals": [
        "수요일 공개 배포 시도는 내부 stretch goal로만 다뤄졌고, 공식 공개 목표로 확정되지 않음."
      ]
    },
    "non_decisions": [
      "README 설치 단계 검토는 필요하다는 코멘트만 있었고, 책임자·최종 담당자·마감 기한이 확정되지 않음."
    ],
    "risks": [
      "생성된 tarball 경로가 잘못되면 릴리스가 지연될 수 있음.",
      "README 설치 절차가 최신이 아니면 릴리스 노트가 사용자에게 오도될 수 있음."
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 stretch goal 언급 여부는 결정되지 않음."
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST 전까지 스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로 확인",
      "due": "미정",
      "status": "확정(기준 이벤트 기반)",
      "source_certainty": "높음"
    },
    {
      "owner": "미지정",
      "task": "README 설치 스텝 검토",
      "due": "목요일(가능 시) / 미확정",
      "status": "미확정",
      "source_certainty": "중간"
    }
  ],
  "followup_note": {
    "check_next": [
      "금요일 10:00 KST 기준 스모크 테스트 통과 여부와 결과 공유 내용 확인",
      "금요일 12:00 KST 이전 Doyun의 실패 트리아지 노트 작성 완료 확인",
      "Hara의 tarball 경로 검증이 실제로 완료되었는지 확인",
      "최종 릴리스 승인 권한자(owner) 지정 여부 확정",
      "릴리스 노트에 수요일 stretch goal을 포함할지 여부 결정",
      "README 검토 책임자와 검토 완료 기준/기한을 확정"
    ],
    "do_not_invent": [
      "고객명, 예산, 보안 사고, 서비스 장애, 법적 승인 요구사항은 미팅에서 언급되지 않아 임의 생성 금지",
      "미팅에 없는 최종 승인 권한자·책임자·마감일은 추측해 채우지 않음",
      "현재 미확정 항목(README 검토 담당자/기한, 릴리스 노트 포함 문구)은 임의로 단정하지 않음"
    ]
  },
  "non_invention_rules": [
    "공개-safe 합성 fixture에 명시된 내용만 반영하고 외부 추정치를 추가하지 않는다.",
    "미확인 사실(고객, 예산, 보안, 장애, 법무/컴플라이언스, 미확정 owner/마감일)을 생성하지 않는다.",
    "요약은 문장 간 결합만 허용하고, 새롭고 본문에 없는 정책/결정/근거를 추가하지 않는다."
  ]
}
